List<[[SLOT record_type]]> mergeRanges(List<({int start, int end})> ranges) {
  if (ranges.isEmpty) return [];

  var sorted = List<({int start, int end})>.from(ranges);
  sorted.sort((a, b) => [[SLOT sort_compare]]);

  var merged = <({int start, int end})>[sorted[0]];

  for (var i = 1; i < sorted.length; i++) {
    var current = sorted[i];
    var last = merged.last;

    if ([[SLOT overlap_check]]) {
      merged[merged.length - 1] = (start: last.start, end: [[SLOT max_end]]);
    } else {
      merged.add(current);
    }
  }

  return merged;
}
